  h+=`</div>`;
  h+=`<div class="result-question">${esc(q)}</div>`;
  h+=`</div>`;
  h+=`<div class="result-disclaimer">卦象解读仅供娱乐参考，请勿作为现实决策依据。</div>`;

  // --- AI Section (first!) ---
  h+=`<div class="section ai-result-section" id="ai-section">`;
  h+=`<div class="section-label">卦象解读</div>`;
