  h+=`<div class="hex-card"><div class="hex-svg">${hexSVG(bg.upper,bg.lower,0,80)}</div>`;
  h+=`<div class="hex-name">第${bg.id}卦 · ${bg.name}</div>`;
  h+=`<div class="hex-full">${bg.full_name}</div><div class="hex-jijing placeholder">占位</div></div>`;
  h+=`</div>`;
  h+=`<div class="hex-caption">左为本卦（第${movingYao}爻动），右为变卦</div>`;
  h+=`</div>`;

  // --- Moving Yao with expandable full Yao text ---
  h+=`<div class="section" id="moving-section">`;
