  if(bg.gua_ci_translation) h+=`<span class="translation">【译文】${bg.gua_ci_translation}</span>`;
  h+=`</div></div>`;

  // --- Gua Ci & Xiang Ci with translations ---
  h+=`<div class="section" id="classic-section">`;
  h+=`<div class="section-label">4 原文译注作参考</div>`;
  h+=`<div class="guide-note"><strong>回看原文：</strong>卦辞看整件事的大方向，象辞看可借鉴的处世姿态；原文可作文化依据，译文更适合直接理解。</div>`;
  h+=`<details class="learn-details" open><summary>查看本卦卦辞、象辞</summary><div class="learn-details-body">`;
