  if(mg.gua_ci_translation) h+=`<span class="translation">【译文】${mg.gua_ci_translation}</span></div>`;
  else h+=`</div>`;
  h+=`<div class="text-block secondary" style="margin-top:.6rem">大象：${mg.xiang_ci}`;
  if(mg.xiang_ci_translation) h+=`<span class="translation">【译文】${mg.xiang_ci_translation}</span></div>`;
