  // Right info
  h+=`</div></div><div class="time-group"><div class="time-group-title">干支与上下卦象意</div><div class="seal-detail">`;
  h+=`<div class="seal-note"><div class="il">干支批注</div><div class="iv">${gzAnnotation(ganzhi)}</div></div>`;
  h+=`<div class="trigram-grid">`;
  h+=`<div class="trigram-card"><div class="trigram-title">上卦 · ${u.name}</div><div class="trigram-meta">`;
