async function loadHistory(){
  const token=localStorage.getItem('yj_token');
  const listEl=document.getElementById('history-list');
  const detailEl=document.getElementById('history-detail');
  listEl.style.display='block';
  detailEl.classList.remove('open');
  if(!token){listEl.innerHTML='<div class="history-empty">请先登录</div>';return}
  listEl.innerHTML='<div class="history-empty">加载中……</div>';
  try{
    const res=await fetch(BACKEND_URL+'/api/history?page=1&page_size=20',{headers:{'Authorization':'Bearer '+token}});
    if(res.status===401){doLogout();listEl.innerHTML='<div class="history-empty">登录已过期，请重新登录</div>';return}
    if(!res.ok){listEl.innerHTML='<div class="history-empty">加载失败</div>';return}
    const data=await readJsonResponse(res);
    if(!data.records||!data.records.length){listEl.innerHTML='<div class="history-empty">暂无记录</div>';return}
    listEl.innerHTML=data.records.map(r=>{
      const t=r.created_at?new Date(r.created_at).toLocaleString('zh-CN',{month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}):'';
      const q=r.question||'';
      return`<div class="history-item" onclick="openHistoryDetail(${Number(r.id)})">
        <div class="hi-question" title="${esc(q)}">${esc(q)}</div>
        <div class="hi-meta">${t}</div>
      </div>`;
    }).join('');
  }catch(e){listEl.innerHTML='<div class="history-empty">加载失败</div>'}
}

