/* ===== Utilities ===== */
function pN(p){return['','初','二','三','四','五','上'][p]}
function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML}
function renderAIInline(s){
  return esc(s).replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>');
}
function renderAIContent(markdown){
  const lines=String(markdown||'').replace(/\r\n?/g,'\n').split('\n');
  const out=[];
  let para=[],list=null,summary=[];
  const flushPara=()=>{
    if(!para.length)return;
    out.push('<p>'+renderAIInline(para.join(' '))+'</p>');
    para=[];
  };
  const flushList=()=>{
    if(!list)return;
    out.push('<'+list.type+'>'+list.items.map(x=>'<li>'+renderAIInline(x)+'</li>').join('')+'</'+list.type+'>');
    list=null;
  };
  const flushSummary=()=>{
    if(!summary.length)return;
    out.push('<div class="ai-summary-grid">'+summary.map(item=>
      '<div class="ai-summary-card"><div class="summary-label">'+renderAIInline(item.label)+'</div><div class="summary-text">'+renderAIInline(item.text)+'</div></div>'
    ).join('')+'</div>');
    summary=[];
  };
  const pushList=(type,text)=>{
    flushPara();flushSummary();
    if(!list||list.type!==type)flushList(),list={type,items:[]};
    list.items.push(text);
  };
  lines.forEach(raw=>{
    const line=raw.trim();
    if(!line){flushPara();flushList();flushSummary();return}
    let m=line.match(/^(#{1,3})\s+(.+)$/);
    if(m){flushPara();flushList();flushSummary();out.push('<h3>'+renderAIInline(m[2])+'</h3>');return}
    m=line.match(/^(决策摘要|明确建议|卦象依据|动爻变化|动爻与变卦|时势补充|五行时势)[：:]\s*$/);
    if(m){flushPara();flushList();flushSummary();out.push('<h3>'+renderAIInline(m[1])+'</h3>');return}
    m=line.match(/^(当前态势|关键阻力|建议动作)[：:]\s*(.+)$/);
    if(m){flushPara();flushList();summary.push({label:m[1],text:m[2]});return}
    m=line.match(/^(留意项|小提示|风险提示)[：:]\s*(.+)$/);
    if(m){flushPara();flushList();flushSummary();out.push('<div class="ai-callout"><span class="callout-label">'+renderAIInline(m[1])+'</span>'+renderAIInline(m[2])+'</div>');return}
    m=line.match(/^[-*]\s+(.+)$/);
    if(m){pushList('ul',m[1]);return}
    m=line.match(/^\d+[.)]\s+(.+)$/);
    if(m){pushList('ol',m[1]);return}
    flushList();flushSummary();
    para.push(line);
  });
  flushPara();flushList();flushSummary();
  return out.join('');
}

