function normalizeHistoryRecord(record){
  const rawQuestion=String(record?.question||'').trim();
  const match=rawQuestion.match(/^【分类：([^】]+)】\s*(.*)$/);
  const category=String(record?.category||match?.[1]||'其他').trim()||'其他';
  const question=(match?match[2]:rawQuestion).trim()||rawQuestion;
  return {...record,displayCategory:category,displayQuestion:question};
}

