function validateTokenFreshness(){
  const token=localStorage.getItem('yj_token');
  if(!token)return false;
  try{
    const payload=JSON.parse(atob(token.split('.')[1]));
    if(payload.exp&&payload.exp*1000<Date.now()){doLogout();return false}
    return true;
  }catch(_){doLogout();return false}
}

function buildShareText(record){
  const normalized=record?normalizeHistoryRecord(record):null;
  const q=normalized?.displayQuestion||cur?.displayQuestion||'';
  const ai=(record&&record.ai_response)||'';
  return ['清风起卦',q&&'所问：'+q,ai&&'解读：'+ai.slice(0,220)].filter(Boolean).join('\n\n');
}

async function copyShareText(record){
  const text=buildShareText(record);
  try{
    await navigator.clipboard.writeText(text);
    return true;
  }catch(_){
    const box=document.createElement('textarea');
    box.value=text;document.body.appendChild(box);box.select();
    const ok=document.execCommand('copy');
    box.remove();
    return ok;
  }
}

async function shareCurrent(record){
  const text=buildShareText(record);
  if(navigator.share){
    try{await navigator.share({title:'清风起卦',text});return}catch(_){}
  }
  await copyShareText(record);
  alert('已复制分享内容');
}

function startDivine(){
  const input=document.getElementById('question-input');
  const q=input.value.trim();
  if(!q){input.focus();return}
  if(q.length>QUESTION_MAX_LENGTH){input.focus();return}
  document.getElementById('btn-divine').disabled=true;
  const now=new Date(),dv=divine(now);
  cur=buildResult(q,dv,{category:getSelectedCategory()});

  const inp=document.getElementById('input-state');
  const ld=document.getElementById('loading-state');
  inp.style.display='none';
  ld.classList.add('show');

  const hexEl=document.getElementById('loading-hex');
  hexEl.innerHTML='';
  const mg=findGua(dv.upper,dv.lower);
  const ll=BL[mg.lower],ul=BL[mg.upper],al=[...ll,...ul];
  for(let i=5;i>=0;i--){
    const div=document.createElement('div');
    div.className='loading-yao'+(al[i]?' yang':' yin');
    if(i+1===dv.movingYao)div.classList.add('moving');
    div.style.bottom=(10+i*30)+'px';
    hexEl.appendChild(div);
  }
  hexEl.querySelectorAll('.loading-yao').forEach((ln,i)=>setTimeout(()=>ln.classList.add('visible'),200+i*250));
  setTimeout(()=>document.getElementById('loading-text').classList.add('show'),200+6*250+100);
  setTimeout(()=>{
    ld.classList.remove('show');
    const rs=document.getElementById('result-state');
    rs.innerHTML=cur.html;
    rs.className='show';
    setResultView(true);
    initResultNavigation();
    if(localStorage.getItem('yj_token'))callAI(cur.q,cur.mg,cur.bg,cur.my,cur.dv);
    window.scrollTo({top:0,behavior:'smooth'});
  },2300);
}

async function callAI(q,mg,bg,my,dv){
  const token=localStorage.getItem('yj_token');
  if(!token)return;
  const el=document.getElementById('ai-output');
  el.className='ai-loading';
  el.innerHTML='正在推演卦象，请稍候……<br><span>通常需要十几秒，完成后会自动保存到历史。</span>';

  const{ganzhi:gz,solar}=dv;
  const u=YJ.bagua[String(mg.upper)],l=YJ.bagua[String(mg.lower)];
  const hexagramData={
    solar:solar,lunar:dv.lunar,
    ganzhi:{year:{gan:gz.year.gan,zhi:gz.year.zhi},month:{gan:gz.month.gan,zhi:gz.month.zhi},day:{gan:gz.day.gan,zhi:gz.day.zhi,ganIdx:gz.day.ganIdx,zhiIdx:gz.day.zhiIdx},hour:{gan:gz.hour.gan,zhi:gz.hour.zhi,ganIdx:gz.hour.ganIdx,zhiIdx:gz.hour.zhiIdx}},
    upper:dv.upper,lower:dv.lower,movingYao:my,
    benGua:{id:mg.id,name:mg.name,full_name:mg.full_name,jijing:mg.jijing,gua_ci:mg.gua_ci,gua_ci_translation:mg.gua_ci_translation,xiang_ci:mg.xiang_ci,xiang_ci_translation:mg.xiang_ci_translation,yaoci:mg.yaoci,upper_name:u.name,upper_nature:u.nature,upper_wuxing:u.wuxing,lower_name:l.name,lower_nature:l.nature,lower_wuxing:l.wuxing},
    bianGua:{id:bg.id,name:bg.name,full_name:bg.full_name,gua_ci:bg.gua_ci,gua_ci_translation:bg.gua_ci_translation}
  };
  const controller=new AbortController();
  const timeoutId=setTimeout(()=>controller.abort(),95000);
  try{
    const res=await fetch(BACKEND_URL+'/api/divine',{
      method:'POST',
      headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},
      body:JSON.stringify({question:q,hexagram_data:hexagramData,category:cur?.category||'',client_version:CLIENT_VERSION}),
      signal:controller.signal
    });
    let data={};
    try{data=await res.json()}catch(_){}
    if(res.status===401){doLogout();el.className='ai-configure-hint';el.innerHTML="<div>登录已过期，请重新登录。</div><br><button class=\"btn-inline\" onclick=\"showAuth('login')\">重新登录</button>";return}
    if(res.status===403){el.className='ai-error';el.textContent=data.error||'今日 AI 解读次数已用完。';return}
    if(res.status===504){el.className='ai-error';el.textContent=data.error||'AI 服务响应超时，请稍后重试。';return}
    if(res.status===502){el.className='ai-error';el.textContent=data.error||'AI 服务调用失败，请稍后重试。';return}
    if(!res.ok)throw new Error(data.error||'服务异常 ('+res.status+')');
    el.className='ai-content';
    el.innerHTML=renderAIContent(data.ai_response||'');
    if(cur)cur.recordId=data.record_id;
    if(data.remaining!=null)updateQuota(data.remaining);
  }catch(e){
    el.className='ai-error';
    el.textContent=e.name==='AbortError'?'AI 服务响应超时，请稍后重试。':'AI 调用失败：'+e.message;
  }finally{clearTimeout(timeoutId)}
}

function toggleHistory(){
  const sb=document.getElementById('history-sidebar');
  const ov=document.getElementById('history-overlay');
  const isOpen=sb.classList.contains('open');
  setDialogOpen(sb,!isOpen);
  setDialogOpen(ov,!isOpen);
  if(isOpen){showHistoryList(false);return}
  lastFocusedBeforeDialog=document.activeElement;
  showHistoryList(false);
  loadHistory();
  setTimeout(()=>focusFirstControl(sb),0);
}

async function loadHistory(){
  const token=localStorage.getItem('yj_token');
  const listEl=document.getElementById('history-list');
  const detailEl=document.getElementById('history-detail');
  const pager=document.getElementById('history-pager');
  listEl.style.display='block';
  detailEl.classList.remove('open');
  if(!token){listEl.innerHTML='<div class="history-empty">请先登录</div>';pager.innerHTML='';return}
  listEl.innerHTML='<div class="history-empty">加载中……</div>';
  const params=new URLSearchParams({page:String(historyState.page),page_size:String(HISTORY_PAGE_SIZE)});
  if(historyState.q)params.set('q',historyState.q);
  if(historyState.category)params.set('category',historyState.category);
  try{
    const res=await fetch(BACKEND_URL+'/api/history?'+params.toString(),{headers:{'Authorization':'Bearer '+token}});
    if(res.status===401){doLogout();listEl.innerHTML='<div class="history-empty">登录已过期，请重新登录</div>';pager.innerHTML='';return}
    if(!res.ok){listEl.innerHTML='<div class="history-empty">加载失败</div>';pager.innerHTML='';return}
    const data=await readJsonResponse(res);
    historyState.total=Number(data.total||0);
    const records=data.records||[];
    if(!records.length){listEl.innerHTML='<div class="history-empty">暂无记录</div>';pager.innerHTML='';return}
    listEl.innerHTML=records.map(r=>{
      const item=normalizeHistoryRecord(r);
      const fav=isFavorite(r.id);
      const t=r.created_at?new Date(r.created_at).toLocaleString('zh-CN',{month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}):'';
      return `<div class="history-item${fav?' is-favorite':''}" role="button" tabindex="0" onclick="openHistoryDetail(${Number(r.id)})" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();openHistoryDetail(${Number(r.id)})}">
        <div class="hi-topline"><span class="history-category-tag">${esc(item.displayCategory)}</span><span class="hi-meta">${t}${fav?' · 已收藏':''}</span></div>
        <div class="hi-question" title="${esc(item.displayQuestion)}">${esc(item.displayQuestion)}</div>
      </div>`;
    }).join('');
    const pages=Math.max(Math.ceil(historyState.total/HISTORY_PAGE_SIZE),1);
    pager.innerHTML=`<button type="button" ${historyState.page<=1?'disabled':''} onclick="historyState.page--;loadHistory()">上一页</button><span>${historyState.page}/${pages} · 共 ${historyState.total} 条</span><button type="button" ${historyState.page>=pages?'disabled':''} onclick="historyState.page++;loadHistory()">下一页</button>`;
  }catch(e){listEl.innerHTML='<div class="history-empty">加载失败</div>';pager.innerHTML=''}
}

function showHistoryList(reload){
  const listEl=document.getElementById('history-list');
  const detailEl=document.getElementById('history-detail');
  detailEl.classList.remove('open');
  detailEl.innerHTML='';
  listEl.style.display='block';
  document.getElementById('history-pager').style.display='';
  if(reload)loadHistory();
}

function closeHistoryPanel(){
  setDialogOpen(document.getElementById('history-sidebar'),false);
  setDialogOpen(document.getElementById('history-overlay'),false);
  showHistoryList(false);
  if(lastFocusedBeforeDialog&&lastFocusedBeforeDialog.focus)lastFocusedBeforeDialog.focus();
}

function showHistoryResult(record){
  const item=normalizeHistoryRecord(record);
  const dv=buildDvFromHistory(record);
  cur=buildResult(item.displayQuestion||'',dv,{mode:'history',aiResponse:record.ai_response||'该记录暂无解卦内容',category:item.displayCategory||''});
  closeHistoryPanel();
  document.getElementById('input-state').style.display='none';
  document.getElementById('loading-state').classList.remove('show');
  const rs=document.getElementById('result-state');
  rs.innerHTML=cur.html;
  rs.className='show';
  setResultView(true);
  initResultNavigation();
  window.scrollTo({top:0,behavior:'smooth'});
}

async function openHistoryDetail(id){
  const token=localStorage.getItem('yj_token');
  const detailEl=document.getElementById('history-detail');
  if(!token){detailEl.innerHTML='<div class="history-empty">请先登录</div>';return}
  try{
    const res=await fetch(BACKEND_URL+'/api/history/'+id,{headers:{'Authorization':'Bearer '+token}});
    if(res.status===401){doLogout();document.getElementById('history-list').innerHTML='<div class="history-empty">登录已过期，请重新登录</div>';return}
    if(!res.ok){document.getElementById('history-list').innerHTML='<div class="history-empty">加载失败</div>';return}
    const record=await readJsonResponse(res);
    showHistoryResult(record);
  }catch(e){
    document.getElementById('history-list').innerHTML='<div class="history-empty">加载失败</div>';
  }
}

function initEnhancements(){
  validateTokenFreshness();
  const input=document.getElementById('question-input');
  if(input){input.addEventListener('input',updateQuestionCount);updateQuestionCount()}
  document.querySelectorAll('.template-chip').forEach(btn=>btn.addEventListener('click',()=>applyQuestionTemplate(btn.dataset.template||'')));
  syncCategoryKeyboard();
  document.getElementById('history-search')?.addEventListener('input',e=>{
    clearTimeout(window.__yjHistorySearchTimer);
    window.__yjHistorySearchTimer=setTimeout(()=>{historyState.q=e.target.value.trim();historyState.page=1;loadHistory()},250);
  });
  document.getElementById('history-category')?.addEventListener('change',e=>{historyState.category=e.target.value;historyState.page=1;loadHistory()});
  document.addEventListener('keydown',event=>{
    if(event.key==='Escape'){
      if(document.getElementById('auth-overlay')?.classList.contains('open'))closeAuth();
      if(document.getElementById('history-sidebar')?.classList.contains('open'))closeHistoryPanel();
    }
  });
}

initEnhancements();
